#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int value;
    struct Node* left;
    struct Node* right;
} Node;

typedef struct BST {
    Node* root;
} BST;

Node* createNode(int value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->value = value;
    node->left = NULL;
    node->right = NULL;
    return node;
}

void insert(BST* bst, int value) {
    if (!bst->root) {
        bst->root = createNode(value);
    } else {
        Node* current = bst->root;
        while (1) {
            if (value < current->value) {
                if (!current->left) {
                    current->left = createNode(value);
                    break;
                }
                current = current->left;
            } else {
                if (!current->right) {
                    current->right = createNode(value);
                    break;
                }
                current = current->right;
            }
        }
    }
}

void inorderRecursive(Node* node, int* result, int* index) {
    if (node) {
        inorderRecursive(node->left, result, index);
        result[(*index)++] = node->value;
        inorderRecursive(node->right, result, index);
    }
}

int* inorder(BST* bst, int* size) {
    int* result = (int*)malloc(100 * sizeof(int));
    int index = 0;
    inorderRecursive(bst->root, result, &index);
    *size = index;
    return result;
}

void freeTree(Node* node) {
    if (node) {
        freeTree(node->left);
        freeTree(node->right);
        free(node);
    }
}

int main() {
    BST bst = {NULL};
    int values[] = {10, 5, 15, 3, 7};
    for (int i = 0; i < 5; i++) {
        insert(&bst, values[i]);
    }
    int size;
    int* result = inorder(&bst, &size);
    printf("Inorder Traversal: [");
    for (int i = 0; i < size; i++) {
        printf("%d", result[i]);
        if (i < size - 1) printf(", ");
    }
    printf("]\n");
    free(result);
    freeTree(bst.root);
    return 0;
}
